import eslint from '@eslint/js';
import tseslint from 'typescript-eslint';
export default tseslint.config({ ignores: ['**/dist/**', '**/coverage/**'] }, eslint.configs.recommended, ...tseslint.configs.recommendedTypeChecked.map((c) => ({ ...c, files: ['**/*.ts', '**/*.tsx'], languageOptions: { ...c.languageOptions, parserOptions: { projectService: true, tsconfigRootDir: import.meta.dirname } } })));

BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TYPE user_status AS ENUM ('active','invited','disabled');
CREATE TYPE project_status AS ENUM ('draft','active','archived');
CREATE TYPE job_status AS ENUM ('queued','active','completed','failed','dead');
CREATE TYPE approval_status AS ENUM ('pending','approved','rejected');
CREATE TABLE organizations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL CHECK(length(name)<=200), region text NOT NULL DEFAULT 'us-east-1', plan text NOT NULL DEFAULT 'starter', settings jsonb NOT NULL DEFAULT '{"ai_enabled":false,"retain_versions":10}', created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE users (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), email text NOT NULL, password_hash text NOT NULL, name text NOT NULL, roles jsonb NOT NULL DEFAULT '["member"]', last_active timestamptz, mfa_enabled boolean NOT NULL DEFAULT false, status user_status NOT NULL DEFAULT 'active', created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(org_id,email));
CREATE TABLE sessions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), user_id uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE, refresh_hash text NOT NULL UNIQUE, expires_at timestamptz NOT NULL, revoked_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE projects (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), title text NOT NULL CHECK(length(title)<=300), timezone text NOT NULL, start_date date, end_date date, status project_status NOT NULL DEFAULT 'draft', version_token uuid NOT NULL DEFAULT gen_random_uuid(), created_by uuid NOT NULL REFERENCES users(id), deleted boolean NOT NULL DEFAULT false, deleted_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CHECK(end_date IS NULL OR start_date IS NULL OR end_date>=start_date));
CREATE TABLE scripts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), project_id uuid NOT NULL REFERENCES projects(id), filename text NOT NULL, storage_key text NOT NULL, mime_type text NOT NULL, size_bytes bigint NOT NULL CHECK(size_bytes>0), version integer NOT NULL DEFAULT 1, status text NOT NULL DEFAULT 'uploaded', search_vector tsvector, version_token uuid NOT NULL DEFAULT gen_random_uuid(), deleted boolean NOT NULL DEFAULT false, deleted_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(project_id,version));
CREATE TABLE script_parses (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), script_id uuid NOT NULL REFERENCES scripts(id) ON DELETE CASCADE, parser_version text NOT NULL, parsed_json jsonb NOT NULL, plain_text text NOT NULL, short_summary text, long_summary text, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE scenes (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), script_id uuid NOT NULL REFERENCES scripts(id) ON DELETE CASCADE, project_id uuid NOT NULL REFERENCES projects(id), scene_number integer NOT NULL, heading text NOT NULL, body text NOT NULL, location_id uuid, estimated_minutes integer NOT NULL DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(script_id,scene_number));
CREATE TABLE people (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), name text NOT NULL, email text, kind text NOT NULL, metadata jsonb NOT NULL DEFAULT '{}', version_token uuid NOT NULL DEFAULT gen_random_uuid(), deleted boolean NOT NULL DEFAULT false, deleted_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE availability_windows (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), person_id uuid NOT NULL REFERENCES people(id) ON DELETE CASCADE, starts_at timestamptz NOT NULL, ends_at timestamptz NOT NULL, available boolean NOT NULL DEFAULT true, CHECK(ends_at>starts_at));
CREATE TABLE locations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), project_id uuid NOT NULL REFERENCES projects(id), name text NOT NULL, address text, latitude numeric(9,6), longitude numeric(9,6), map_provider_id text, version_token uuid NOT NULL DEFAULT gen_random_uuid(), created_at timestamptz NOT NULL DEFAULT now());
ALTER TABLE scenes ADD CONSTRAINT scenes_location_fk FOREIGN KEY(location_id) REFERENCES locations(id);
CREATE TABLE schedules (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), project_id uuid NOT NULL REFERENCES projects(id), name text NOT NULL, version_token uuid NOT NULL DEFAULT gen_random_uuid(), created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE shoot_days (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), schedule_id uuid NOT NULL REFERENCES schedules(id) ON DELETE CASCADE, shoot_date date NOT NULL, call_time time, location_id uuid REFERENCES locations(id), version_token uuid NOT NULL DEFAULT gen_random_uuid(), UNIQUE(schedule_id,shoot_date));
CREATE TABLE schedule_assignments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), shoot_day_id uuid NOT NULL REFERENCES shoot_days(id) ON DELETE CASCADE, scene_id uuid REFERENCES scenes(id), person_id uuid REFERENCES people(id), starts_at timestamptz, ends_at timestamptz, UNIQUE(shoot_day_id,scene_id,person_id));
CREATE TABLE budgets (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), project_id uuid NOT NULL REFERENCES projects(id), name text NOT NULL, currency char(3) NOT NULL, version_token uuid NOT NULL DEFAULT gen_random_uuid(), created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE budget_items (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), budget_id uuid NOT NULL REFERENCES budgets(id) ON DELETE CASCADE, category text NOT NULL, description text NOT NULL, quantity numeric(12,2) NOT NULL CHECK(quantity>=0), unit_cost numeric(14,2) NOT NULL CHECK(unit_cost>=0), actual_cost numeric(14,2) NOT NULL DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE assets (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), project_id uuid NOT NULL REFERENCES projects(id), name text NOT NULL, kind text NOT NULL, version_token uuid NOT NULL DEFAULT gen_random_uuid(), deleted boolean NOT NULL DEFAULT false, deleted_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE asset_versions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), asset_id uuid NOT NULL REFERENCES assets(id) ON DELETE CASCADE, version integer NOT NULL, storage_key text NOT NULL, preview_key text, mime_type text NOT NULL, size_bytes bigint NOT NULL CHECK(size_bytes BETWEEN 1 AND 209715200), malware_status text NOT NULL DEFAULT 'pending', created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(asset_id,version));
CREATE TABLE comments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), entity_type text NOT NULL, entity_id uuid NOT NULL, author_id uuid NOT NULL REFERENCES users(id), body text NOT NULL CHECK(length(body)<=10000), search_vector tsvector GENERATED ALWAYS AS (to_tsvector('english',body)) STORED, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE approvals (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), entity_type text NOT NULL, entity_id uuid NOT NULL, requested_by uuid NOT NULL REFERENCES users(id), decided_by uuid REFERENCES users(id), status approval_status NOT NULL DEFAULT 'pending', note text, version_token uuid NOT NULL DEFAULT gen_random_uuid(), created_at timestamptz NOT NULL DEFAULT now(), decided_at timestamptz);
CREATE TABLE notifications (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), user_id uuid NOT NULL REFERENCES users(id), kind text NOT NULL, payload jsonb NOT NULL, read_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE audit_logs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), actor_id uuid REFERENCES users(id), action text NOT NULL, entity_type text NOT NULL, entity_id uuid, data jsonb NOT NULL DEFAULT '{}', previous_hash text, immutable_hash text NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE ai_requests (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), user_id uuid REFERENCES users(id), prompt_template_id text NOT NULL, model_id text NOT NULL, prompt_hash text NOT NULL, redacted_snippet text NOT NULL, response_hash text, input_tokens integer NOT NULL DEFAULT 0, output_tokens integer NOT NULL DEFAULT 0, cost_micros bigint NOT NULL DEFAULT 0, cached boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE jobs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), org_id uuid NOT NULL REFERENCES organizations(id), type text NOT NULL, status job_status NOT NULL DEFAULT 'queued', idempotency_key text NOT NULL, payload jsonb NOT NULL, result jsonb, attempts integer NOT NULL DEFAULT 0, correlation_id text NOT NULL, enqueued_by uuid REFERENCES users(id), error text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), UNIQUE(org_id,idempotency_key));
CREATE INDEX projects_org_created_idx ON projects(org_id,created_at DESC); CREATE INDEX scripts_org_project_created_idx ON scripts(org_id,project_id,created_at DESC); CREATE INDEX scenes_script_number_idx ON scenes(script_id,scene_number); CREATE INDEX comments_search_idx ON comments USING gin(search_vector); CREATE INDEX scripts_search_idx ON scripts USING gin(search_vector); CREATE INDEX jobs_status_idx ON jobs(status,created_at); CREATE INDEX notifications_user_idx ON notifications(org_id,user_id,created_at DESC);
CREATE MATERIALIZED VIEW dashboard_aggregates AS SELECT p.org_id,p.id project_id,count(DISTINCT s.id) scenes,count(DISTINCT pe.id) people,count(DISTINCT a.id) assets FROM projects p LEFT JOIN scenes s ON s.project_id=p.id LEFT JOIN people pe ON pe.org_id=p.org_id AND NOT pe.deleted LEFT JOIN assets a ON a.project_id=p.id AND NOT a.deleted WHERE NOT p.deleted GROUP BY p.org_id,p.id;
CREATE UNIQUE INDEX dashboard_aggregates_pk ON dashboard_aggregates(org_id,project_id);
CREATE FUNCTION app_org_id() RETURNS uuid LANGUAGE sql STABLE AS $$ SELECT nullif(current_setting('app.claims',true),'')::jsonb->>'org_id' $$;
CREATE FUNCTION app_roles() RETURNS jsonb LANGUAGE sql STABLE AS $$ SELECT COALESCE(nullif(current_setting('app.claims',true),'')::jsonb->'roles','[]'::jsonb) $$;
DO $$ DECLARE t text; BEGIN FOREACH t IN ARRAY ARRAY['users','sessions','projects','scripts','script_parses','scenes','people','availability_windows','locations','schedules','shoot_days','schedule_assignments','budgets','budget_items','assets','asset_versions','comments','approvals','notifications','audit_logs','ai_requests','jobs'] LOOP EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY',t); EXECUTE format('ALTER TABLE %I FORCE ROW LEVEL SECURITY',t); EXECUTE format('CREATE POLICY org_isolation ON %I USING (org_id=app_org_id()) WITH CHECK (org_id=app_org_id())',t); END LOOP; END $$;
CREATE POLICY finance_budget_items ON budget_items AS RESTRICTIVE USING (app_roles() ?| ARRAY['admin','finance']) WITH CHECK (app_roles() ?| ARRAY['admin','finance']);
CREATE POLICY approval_decisions ON approvals AS RESTRICTIVE USING (true) WITH CHECK (app_roles() ?| ARRAY['admin','producer','finance']);
CREATE POLICY audit_read ON audit_logs AS RESTRICTIVE FOR SELECT USING (app_roles() ? 'admin');
CREATE FUNCTION prevent_audit_mutation() RETURNS trigger LANGUAGE plpgsql AS $$ BEGIN RAISE EXCEPTION 'audit logs are immutable'; END $$;
CREATE TRIGGER audit_immutable BEFORE UPDATE OR DELETE ON audit_logs FOR EACH ROW EXECUTE FUNCTION prevent_audit_mutation();
COMMIT;

