export type Role = 'admin' | 'producer' | 'finance' | 'crew' | 'member' | 'viewer';
export interface AuthClaims { sub: string; org_id: string; roles: Role[]; session_id: string }
export interface Provenance { model_used: string; prompt_template_id: string; prompt_hash: string; generated_at: string; token_usage: { input: number; output: number }; cached: boolean }
export interface ApiError { code: string; message: string; details?: unknown }
export interface Job { id: string; status: 'queued' | 'active' | 'completed' | 'failed' | 'dead'; result?: unknown }

{
  "name": "@studioforge/api",
  "version": "1.0.0",
  "type": "module",
  "scripts": { "dev": "tsx watch src/server.ts", "build": "tsc", "start": "node dist/server.js", "typecheck": "tsc --noEmit", "test": "vitest run --coverage" },
  "dependencies": { "@aws-sdk/client-s3": "3.709.0", "@aws-sdk/s3-request-presigner": "3.709.0", "@fastify/cors": "10.0.1", "@fastify/jwt": "9.0.2", "@fastify/rate-limit": "10.1.1", "argon2": "0.41.1", "fastify": "5.2.0", "ioredis": "5.4.1", "pg": "8.13.1", "zod": "3.24.1" },
  "devDependencies": { "@types/pg": "8.11.10", "@vitest/coverage-v8": "2.1.8" }
}

import { createHash, randomUUID } from 'node:crypto';
export const estimateCost = (items: ReadonlyArray<{ quantity: number; unitCost: number }>): number => Math.round(items.reduce((sum, i) => sum + i.quantity * i.unitCost, 0) * 100) / 100;
export const parseScenes = (text: string) => text.split(/\n(?=(?:INT\.|EXT\.|INT\/EXT\.)\s)/i).map((body, index) => ({ scene_number: index + 1, heading: body.split('\n')[0]?.trim() || `SCENE ${index + 1}`, body: body.trim() })).filter((scene) => scene.body.length > 0);
export const opaqueCursor = (date: string, id: string) => Buffer.from(JSON.stringify({ date, id })).toString('base64url');
export const versionToken = () => randomUUID();
export const immutableHash = (previous: string | null, value: unknown) => createHash('sha256').update(`${previous ?? ''}:${JSON.stringify(value)}`).digest('hex');

import Fastify from 'fastify';
import cors from '@fastify/cors';
import jwt from '@fastify/jwt';
import rateLimit from '@fastify/rate-limit';
import argon2 from 'argon2';
import { randomBytes, randomUUID, createHash } from 'node:crypto';
import pg from 'pg';
import Redis from 'ioredis';
import { S3Client, PutObjectCommand, GetObjectCommand } from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
const env = { database: process.env.DATABASE_URL ?? '', redis: process.env.REDIS_URL ?? 'redis://localhost:6379', secret: process.env.JWT_SECRET ?? '', bucket: process.env.S3_BUCKET ?? '', region: process.env.AWS_REGION ?? 'us-east-1', ai: process.env.AI_GATEWAY_URL ?? 'http://localhost:4001' };
if (!env.database || env.secret.length < 32 || !env.bucket) throw new Error('DATABASE_URL, S3_BUCKET and a 32-character JWT_SECRET are required');
const pool = new pg.Pool({ connectionString: env.database, max: 20 });
const redis = new Redis(env.redis, { maxRetriesPerRequest: 2 });
const s3 = new S3Client({ region: env.region, endpoint: process.env.S3_ENDPOINT, forcePathStyle: Boolean(process.env.S3_ENDPOINT) });
const app = Fastify({ logger: { redact: ['req.headers.authorization', 'password', 'refresh_token'] }, bodyLimit: 21 * 1024 * 1024, trustProxy: true });
await app.register(cors, { origin: process.env.WEB_ORIGIN?.split(',') ?? false, credentials: true });
await app.register(rateLimit, { max: 200, timeWindow: '1 minute' });
await app.register(jwt, { secret: env.secret, sign: { expiresIn: process.env.ACCESS_TOKEN_TTL ?? '15m' } });
app.addHook('onRequest', async (req, reply) => { const id = String(req.headers['x-correlation-id'] ?? randomUUID()); req.headers['x-correlation-id'] = id; reply.header('X-Correlation-ID', id).header('Strict-Transport-Security', 'max-age=31536000; includeSubDomains'); });
type Claims={sub:string;org_id:string;roles:string[];session_id:string};
const auth = async (req: Parameters<typeof app.authenticate>[0] & { user: Claims }, reply: Parameters<typeof app.authenticate>[1]) => { try { await req.jwtVerify(); if (await redis.get(`revoked:${req.user.session_id}`)) return reply.code(401).send({ code:'SESSION_REVOKED', message:'Session revoked' }); const pathOrg=(req.params as Record<string,string>).orgId; if(pathOrg && pathOrg!==req.user.org_id) return reply.code(403).send({code:'TENANT_DENIED',message:'Cross-organization access denied'}); } catch { return reply.code(401).send({code:'UNAUTHORIZED',message:'Valid access token required'}); } };
app.decorate('authenticate', auth);
app.setErrorHandler((error, _req, reply) => { const status=Number((error as {statusCode?:number}).statusCode ?? 500); reply.code(status).send({code:status===500?'INTERNAL_ERROR':'REQUEST_ERROR',message:status===500?'Request failed':error.message}); });
async function scoped<T>(claims:Claims, fn:(c:pg.PoolClient)=>Promise<T>):Promise<T>{ const c=await pool.connect(); try { await c.query('BEGIN'); await c.query("SELECT set_config('app.claims',$1,true)",[JSON.stringify(claims)]); const out=await fn(c); await c.query('COMMIT'); return out; } catch(e){await c.query('ROLLBACK');throw e;} finally{c.release();} }
const hash=(v:string)=>createHash('sha256').update(v).digest('hex');
const tokens=async(user:{id:string;org_id:string;roles:string[]}, sessionId=randomUUID())=>{ const refresh=randomBytes(48).toString('base64url'); await pool.query('INSERT INTO sessions(id,org_id,user_id,refresh_hash,expires_at) VALUES($1,$2,$3,$4,now()+($5||\' days\')::interval)',[sessionId,user.org_id,user.id,hash(refresh),process.env.REFRESH_TOKEN_DAYS??'30']); return {access_token:app.jwt.sign({sub:user.id,org_id:user.org_id,roles:user.roles,session_id:sessionId}),refresh_token:`${sessionId}.${refresh}`}; };
app.get('/health',async()=>({status:'ok'}));
app.post('/api/v1/auth/signup',async(req,reply)=>{const b=req.body as {org_name:string;email:string;password:string;name:string};if(b.password.length<12)return reply.code(400).send({code:'WEAK_PASSWORD',message:'Password must contain at least 12 characters'});const c=await pool.connect();try{await c.query('BEGIN');const o=await c.query('INSERT INTO organizations(name) VALUES($1) RETURNING id',[b.org_name]);const u=await c.query("INSERT INTO users(org_id,email,password_hash,name,roles) VALUES($1,lower($2),$3,$4,'[\"admin\"]') RETURNING id,org_id,roles",[o.rows[0].id,b.email,await argon2.hash(b.password),b.name]);await c.query('COMMIT');return reply.code(201).send(await tokens(u.rows[0]));}catch(e){await c.query('ROLLBACK');throw e;}finally{c.release();}});
app.post('/api/v1/auth/login',async(req,reply)=>{const b=req.body as {email:string;password:string};const q=await pool.query('SELECT id,org_id,password_hash,roles,status FROM users WHERE email=lower($1)',[b.email]);const u=q.rows[0];if(!u||u.status!=='active'||!await argon2.verify(u.password_hash,b.password))return reply.code(401).send({code:'INVALID_CREDENTIALS',message:'Invalid credentials'});return tokens(u);});
app.post('/api/v1/auth/refresh',async(req,reply)=>{const raw=(req.body as {refresh_token:string}).refresh_token;const [id,secret]=raw.split('.');if(!id||!secret)return reply.code(401).send({code:'INVALID_REFRESH',message:'Invalid refresh token'});const c=await pool.connect();try{await c.query('BEGIN');const q=await c.query('SELECT s.*,u.roles FROM sessions s JOIN users u ON u.id=s.user_id WHERE s.id=$1 FOR UPDATE',[id]);const s=q.rows[0];if(!s||s.revoked_at||s.expires_at<new Date()||s.refresh_hash!==hash(secret))throw new Error('invalid');await c.query('UPDATE sessions SET revoked_at=now() WHERE id=$1',[id]);await c.query('COMMIT');await redis.set(`revoked:${id}`,'1','EX',2592000);return tokens({id:s.user_id,org_id:s.org_id,roles:s.roles});}catch{await c.query('ROLLBACK');return reply.code(401).send({code:'INVALID_REFRESH',message:'Refresh token expired or already used'});}finally{c.release();}});
app.post('/api/v1/auth/logout',{preHandler:auth},async(req)=>{const u=req.user as Claims;await pool.query('UPDATE sessions SET revoked_at=now() WHERE id=$1',[u.session_id]);await redis.set(`revoked:${u.session_id}`,'1','EX',2592000);return {ok:true};});
app.post('/api/v1/admin/users/:id/revoke-sessions',{preHandler:auth},async(req,reply)=>{const u=req.user as Claims;if(!u.roles.includes('admin'))return reply.code(403).send({code:'FORBIDDEN',message:'Admin role required'});const q=await scoped(u,c=>c.query('UPDATE sessions SET revoked_at=now() WHERE user_id=$1 AND revoked_at IS NULL RETURNING id',[(req.params as {id:string}).id]));await Promise.all(q.rows.map(r=>redis.set(`revoked:${r.id}`,'1','EX',2592000)));return {revoked:q.rowCount};});
app.get('/api/v1/orgs/:orgId',{preHandler:auth},async(req)=>{const u=req.user as Claims;return (await scoped(u,c=>c.query('SELECT id,name,region,plan,settings,created_at FROM organizations WHERE id=$1',[u.org_id]))).rows[0];});
app.patch('/api/v1/orgs/:orgId/settings',{preHandler:auth},async(req,reply)=>{const u=req.user as Claims;if(!u.roles.includes('admin'))return reply.code(403).send({code:'FORBIDDEN',message:'Admin role required'});return (await pool.query('UPDATE organizations SET settings=settings||$1 WHERE id=$2 RETURNING id,settings',[req.body,u.org_id])).rows[0];});
app.post('/api/v1/orgs/:orgId/projects',{preHandler:auth},async(req,reply)=>{const u=req.user as Claims;const b=req.body as {title:string;timezone:string;start_date?:string;end_date?:string};const q=await scoped(u,c=>c.query('INSERT INTO projects(org_id,title,timezone,start_date,end_date,created_by) VALUES($1,$2,$3,$4,$5,$6) RETURNING *',[u.org_id,b.title,b.timezone,b.start_date??null,b.end_date??null,u.sub]));return reply.code(201).send(q.rows[0]);});
app.get('/api/v1/orgs/:orgId/projects/:projectId',{preHandler:auth},async(req,reply)=>{const u=req.user as Claims;const q=await scoped(u,c=>c.query('SELECT * FROM projects WHERE id=$1 AND NOT deleted',[(req.params as {projectId:string}).projectId]));if(!q.rows[0])return reply.code(404).send({code:'NOT_FOUND',message:'Project not found'});return reply.header('ETag',q.rows[0].version_token).send(q.rows[0]);});
app.patch('/api/v1/orgs/:orgId/projects/:projectId',{preHandler:auth},async(req,reply)=>{const u=req.user as Claims;const p=req.params as {projectId:string};const b=req.body as {title?:string;status?:string;version_token?:string};const v=String(req.headers['if-match']??b.version_token??'');const q=await scoped(u,c=>c.query('UPDATE projects SET title=COALESCE($1,title),status=COALESCE($2,status),version_token=gen_random_uuid(),updated_at=now() WHERE id=$3 AND version_token::text=$4 RETURNING *',[b.title??null,b.status??null,p.projectId,v]));if(!q.rows[0])return reply.code(409).send({code:'VERSION_CONFLICT',message:'Entity changed; fetch the current representation'});return q.rows[0];});
async function upload(req:any,reply:any,kind:'script'|'asset'){const u=req.user as Claims;const b=req.body as {filename:string;mime_type:string;size_bytes:number};const max=kind==='script'?20971520:209715200;if(b.size_bytes<1||b.size_bytes>max)return reply.code(413).send({code:'FILE_TOO_LARGE',message:`Maximum size is ${max} bytes`});const id=randomUUID(),key=`org/${u.org_id}/${kind}s/${id}/${b.filename.replace(/[^a-zA-Z0-9._-]/g,'_')}`;const url=await getSignedUrl(s3,new PutObjectCommand({Bucket:env.bucket,Key:key,ContentType:b.mime_type,ContentLength:b.size_bytes}),{expiresIn:900});return reply.code(201).send({id,upload_url:url,storage_key:key,expires_in:900});}
app.post('/api/v1/orgs/:orgId/projects/:projectId/scripts',{preHandler:auth},r=>upload(r,arguments[1],'script'));
app.post('/api/v1/orgs/:orgId/projects/:projectId/assets',{preHandler:auth},r=>upload(r,arguments[1],'asset'));
app.post('/api/v1/orgs/:orgId/projects/:projectId/scripts/:scriptId/parse',{preHandler:auth},async(req,reply)=>enqueue(req,reply,'parse-script'));
app.post('/api/v1/orgs/:orgId/projects/:projectId/schedules/optimize',{preHandler:auth},async(req,reply)=>enqueue(req,reply,'optimize-schedule'));
app.post('/api/v1/budgets/estimate',{preHandler:auth},async(req,reply)=>enqueue(req,reply,'estimate-budget'));
async function enqueue(req:any,reply:any,type:string){const u=req.user as Claims;const key=String(req.headers['idempotency-key']??randomUUID());const q=await scoped(u,c=>c.query('INSERT INTO jobs(org_id,type,idempotency_key,payload,correlation_id,enqueued_by) VALUES($1,$2,$3,$4,$5,$6) ON CONFLICT(org_id,idempotency_key) DO UPDATE SET idempotency_key=EXCLUDED.idempotency_key RETURNING id,status',[u.org_id,type,key,req.body??{},req.headers['x-correlation-id'],u.sub]));await redis.lpush('studioforge:dispatch',JSON.stringify({jobId:q.rows[0].id,type}));return reply.code(202).send({jobId:q.rows[0].id,status:q.rows[0].status});}
app.get('/api/v1/jobs/:jobId',{preHandler:auth},async(req,reply)=>{const u=req.user as Claims;const q=await scoped(u,c=>c.query('SELECT id,type,status,result,attempts,error,created_at,updated_at FROM jobs WHERE id=$1',[(req.params as {jobId:string}).jobId]));return q.rows[0]??reply.code(404).send({code:'NOT_FOUND',message:'Job not found'});});
app.post('/api/v1/locks',{preHandler:auth},async(req,reply)=>{const u=req.user as Claims;const b=req.body as {entityId:string;ttl:number};const ttl=Math.min(Math.max(b.ttl,5),300),id=randomUUID();const ok=await redis.set(`lock:${u.org_id}:${b.entityId}`,id,'EX',ttl,'NX');if(!ok)return reply.code(409).send({code:'LOCKED',message:'Entity is locked'});return {lockId:id,locked_until:new Date(Date.now()+ttl*1000).toISOString()};});
app.delete('/api/v1/locks/:lockId',{preHandler:auth},async(req)=>{const u=req.user as Claims;const id=(req.params as {lockId:string}).lockId;const keys=await redis.keys(`lock:${u.org_id}:*`);for(const key of keys)if(await redis.get(key)===id)await redis.del(key);return {released:true};});
app.get('/api/v1/assets/:id/preview',{preHandler:auth},async(req,reply)=>{const u=req.user as Claims;const q=await scoped(u,c=>c.query('SELECT preview_key FROM asset_versions WHERE asset_id=$1 AND preview_key IS NOT NULL ORDER BY version DESC LIMIT 1',[(req.params as {id:string}).id]));if(!q.rows[0])return reply.code(404).send({code:'NOT_FOUND',message:'Preview not found'});return {url:await getSignedUrl(s3,new GetObjectCommand({Bucket:env.bucket,Key:q.rows[0].preview_key}),{expiresIn:300})};});
app.post('/api/v1/ai/summarize-script',{preHandler:auth},async(req,reply)=>{const u=req.user as Claims;const response=await fetch(`${env.ai}/v1/summarize`,{method:'POST',headers:{'content-type':'application/json','x-org-id':u.org_id,'x-user-id':u.sub},body:JSON.stringify(req.body)});return reply.code(response.status).send(await response.json());});
app.post('/api/v1/realtime/token',{preHandler:auth},async(req)=>{const u=req.user as Claims;return {token:app.jwt.sign({...u,aud:'realtime'},{expiresIn:'5m'}),expires_in:300,channels:['schedules','comments','notifications','presence']};});
app.listen({port:Number(process.env.PORT??4000),host:'0.0.0.0'}).catch(e=>{app.log.error(e);process.exit(1)});

