const app=Fastify({logger:{redact:['req.headers.authorization']},bodyLimit:2_000_000});const redis=new Redis(process.env.REDIS_URL??'redis://localhost:6379');const pool=new pg.Pool({connectionString:process.env.DATABASE_URL});const sha=(s:string)=>createHash('sha256').update(s).digest('hex');
const redact=(s:string)=>s.replace(/[\w.+-]+@[\w.-]+\.[A-Za-z]{2,}/g,'[EMAIL]').replace(/\+?\d[\d ()-]{7,}\d/g,'[PHONE]').replace(/\b\d{3}-\d{2}-\d{4}\b/g,'[SSN]');
app.post('/v1/summarize',async(req,reply)=>{const org=String(req.headers['x-org-id']??''),user=String(req.headers['x-user-id']??'');if(!org)return reply.code(401).send({code:'UNAUTHORIZED',message:'Trusted organization header required'});const body=req.body as {text:string;length?:'short'|'long'};const clean=redact(body.text).slice(0,100000),template='script-summary-v1',model='provider-default-v1',key=sha(`${clean}:${template}:${model}:${body.length??'short'}`),cached=await redis.get(`ai:${key}`);if(cached)return JSON.parse(cached);const used=Number(await redis.incrby(`ai-quota:${org}:${new Date().toISOString().slice(0,7)}`,clean.length));await redis.expire(`ai-quota:${org}:${new Date().toISOString().slice(0,7)}`,2678400);if(used>5_000_000)return reply.code(429).send({code:'AI_QUOTA_EXCEEDED',message:'Monthly AI compute budget exceeded'});let summary:string;const endpoint=process.env.AI_PROVIDER_URL;if(endpoint&&process.env.AI_PROVIDER_API_KEY){const r=await fetch(endpoint,{method:'POST',headers:{authorization:`Bearer ${process.env.AI_PROVIDER_API_KEY}`,'content-type':'application/json'},body:JSON.stringify({model,prompt:`Summarize the supplied screenplay without inventing facts. ${body.length==='long'?'Return one paragraph.':'Return 2-3 sentences.'}\n${clean}`})});if(!r.ok)return reply.code(503).send({code:'AI_PROVIDER_UNAVAILABLE',message:'AI provider unavailable'});summary=String((await r.json() as {text:string}).text);}else{summary=clean.split(/(?<=[.!?])\s+/).slice(0,body.length==='long'?6:3).join(' ');}const provenance={model_used:model,prompt_template_id:template,prompt_hash:key,generated_at:new Date().toISOString(),token_usage:{input:Math.ceil(clean.length/4),output:Math.ceil(summary.length/4)},cached:false};const result={summary,...provenance};await redis.set(`ai:${key}`,JSON.stringify(result),'EX',86400);await pool.query('INSERT INTO ai_requests(org_id,user_id,prompt_template_id,model_id,prompt_hash,redacted_snippet,response_hash,input_tokens,output_tokens,cached) VALUES($1,$2,$3,$4,$5,$6,$7,$8,$9,false)',[org,user||null,template,model,key,clean.slice(0,200),sha(summary),provenance.token_usage.input,provenance.token_usage.output]);return result;});
