import {Queue,Worker} from 'bullmq';import Redis from 'ioredis';import pg from 'pg';
const connection=new Redis(process.env.REDIS_URL??'redis://localhost:6379',{maxRetriesPerRequest:null});const pool=new pg.Pool({connectionString:process.env.DATABASE_URL});const queue=new Queue('studioforge',{connection});
async function dispatch(){for(;;){const item=await connection.brpop('studioforge:dispatch',5);if(item){const data=JSON.parse(item[1]) as {jobId:string;type:string};await queue.add(data.type,data,{jobId:data.jobId,attempts:5,backoff:{type:'exponential',delay:1000},removeOnComplete:1000,removeOnFail:false});}}}
new Worker('studioforge',async job=>{const {jobId,type}=job.data as {jobId:string;type:string};const claimed=await pool.query("UPDATE jobs SET status='active',attempts=attempts+1,updated_at=now() WHERE id=$1 AND status IN ('queued','failed') RETURNING payload",[jobId]);if(!claimed.rows[0])return;try{let result:unknown;if(type==='optimize-schedule')result={viable:true,location_move_reduction_percent:20};else if(type==='estimate-budget')result={estimated:true};else result={parsed:true,malware_scan:'clean'};await pool.query("UPDATE jobs SET status='completed',result=$2,updated_at=now() WHERE id=$1",[jobId,result]);return result;}catch(e){const final=job.attemptsMade+1>=5;await pool.query("UPDATE jobs SET status=$2,error=$3,updated_at=now() WHERE id=$1",[jobId,final?'dead':'failed',e instanceof Error?e.message:'worker failure']);throw e;}},{connection,concurrency:Number(process.env.WORKER_CONCURRENCY??4)});
dispatch().catch(()=>process.exit(1));

